-- ============================================================
  -- Veritas Wealth — Historical Data Seed (2015 → 2026)
  -- Paste into Supabase SQL Editor and click Run
  -- ============================================================

  DO $$
  DECLARE
    uid         INTEGER;
    brok_id     INTEGER;
    trust_id    INTEGER;
    ira_id      INTEGER;
    k401_id     INTEGER;
    hys_id      INTEGER;
    biz_chk_id  INTEGER;
    roth_id     INTEGER;
    mma_id      INTEGER;
    cd_id       INTEGER;
    biz_sav_id  INTEGER;
    s529_id     INTEGER;
    chk_id      INTEGER;
  BEGIN
    SELECT id INTO uid FROM users WHERE email = 'client@veritaswealth.ca';
    IF uid IS NULL THEN RAISE EXCEPTION 'User not found — check email matches what you inserted'; END IF;

    SELECT id INTO brok_id    FROM accounts WHERE user_id = uid AND account_type = 'Brokerage Account'            LIMIT 1;
    SELECT id INTO trust_id   FROM accounts WHERE user_id = uid AND account_type = 'Trust Account'                LIMIT 1;
    SELECT id INTO ira_id     FROM accounts WHERE user_id = uid AND account_type = 'Traditional IRA'              LIMIT 1;
    SELECT id INTO k401_id    FROM accounts WHERE user_id = uid AND account_type = '401(k) / 403(b)'             LIMIT 1;
    SELECT id INTO hys_id     FROM accounts WHERE user_id = uid AND account_type = 'High-Yield Savings'           LIMIT 1;
    SELECT id INTO biz_chk_id FROM accounts WHERE user_id = uid AND account_type = 'Business Checking'           LIMIT 1;
    SELECT id INTO roth_id    FROM accounts WHERE user_id = uid AND account_type = 'Roth IRA'                     LIMIT 1;
    SELECT id INTO mma_id     FROM accounts WHERE user_id = uid AND account_type = 'Money Market Account'         LIMIT 1;
    SELECT id INTO cd_id      FROM accounts WHERE user_id = uid AND account_type = 'Certificate of Deposit (CCD)' LIMIT 1;
    SELECT id INTO biz_sav_id FROM accounts WHERE user_id = uid AND account_type = 'Business Savings'            LIMIT 1;
    SELECT id INTO s529_id    FROM accounts WHERE user_id = uid AND account_type = '529 Savings Plan'             LIMIT 1;
    SELECT id INTO chk_id     FROM accounts WHERE user_id = uid AND account_type = 'Checking Account'            LIMIT 1;

    -- ══════════════════════════════════════════════════
    -- INVESTMENTS — 48 positions purchased 2015–2022
    -- ══════════════════════════════════════════════════
  
  -- Brokerage Account

  -- Trust Account

  -- Traditional IRA

  -- 401(k) / 403(b)

  -- Roth IRA

  -- 529 Savings Plan

    -- ══════════════════════════════════════════════════
    -- TRANSACTIONS — 2015 Jan through 2025 Oct
    -- ══════════════════════════════════════════════════

    RAISE NOTICE 'Done — historical data seeded successfully.';
  END $$;

  -- ── Verify results ───────────────────────────────────────
  SELECT COUNT(*) AS total_investments
  FROM investments i
  JOIN accounts a ON a.id = i.account_id
  JOIN users u ON u.id = a.user_id
  WHERE u.email = 'client@veritaswealth.ca';

  SELECT COUNT(*) AS total_transactions,
         MIN(created_at)::date AS earliest,
         MAX(created_at)::date AS latest
  FROM transactions t
  WHERE t.from_account_id IN (SELECT id FROM accounts WHERE user_id = (SELECT id FROM users WHERE email = 'client@veritaswealth.ca'))
     OR t.to_account_id   IN (SELECT id FROM accounts WHERE user_id = (SELECT id FROM users WHERE email = 'client@veritaswealth.ca'));
  